// Utilitário para persistir o histórico de arquivos no localStorage

const STORAGE_KEY = 'historicoArquivosEnlacesContratados';

export function salvarHistoricoNoStorage(historico) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(historico));
  } catch (e) {}
}

export function carregarHistoricoDoStorage() {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  } catch (e) {
    return [];
  }
}
